### What This Code Does

This is an obfuscated implementation of the **A* (A-Star) Pathfinding Algorithm**. 

It creates a 20x15 grid, randomly scatters obstacles across it (with a 25% probability), and then calculates the shortest path from the top-left corner `(0,0)` to the bottom-right corner `(19, 14)`. It uses an 8-way movement system (horizontal, vertical, and diagonal moves) and logs the resulting path length, total movement cost, and the number of loop iterations it took to find the path.

### Deobfuscated and Cleaned Code

Here is the exact same logic, completely deobfuscated, with readable variable names, restored control flow, and removed junk strings:

```javascript
// 1. Configuration and Grid Setup
const gridWidth = 20;
const gridHeight = 15;
const config = {
    heuristicType: 'manhattan', // Obfuscated as 'invoice'
    diagonalCost: 1.414,        // Obfuscated as 'purchaseCost'
    straightCost: 1,            // Obfuscated as 'traversalCost'
    maxIterations: 1000,        // Obfuscated as 'minIterations'
    obstacleRatio: 0.25         // Obfuscated as 'clearanceRatio'
};

let grid = [];
for (let y = 0; y < gridHeight; y++) {
    grid[y] = [];
    for (let x = 0; x < gridWidth; x++) {
        // 25% chance of being an obstacle (1), 75% chance of being walkable (0)
        grid[y][x] = Math.random() < config.obstacleRatio ? 1 : 0;
    }
}

// Ensure start and end points are always walkable
const startNode = { x: 0, y: 0 };
const endNode = { x: gridWidth - 1, y: gridHeight - 1 };
grid[startNode.y][startNode.x] = 0;
grid[endNode.y][endNode.x] = 0;

// 2. Helper Functions
function calculateHeuristic(nodeA, nodeB) {
    const dx = Math.abs(nodeA.x - nodeB.x);
    const dy = Math.abs(nodeA.y - nodeB.y);

    if (config.heuristicType === 'manhattan') {
        return dx + dy;
    }
    // Euclidean distance fallback
    return Math.sqrt((dx * dx) + (dy * dy));
}

function getNeighbors(node) {
    const neighbors = [];
    const moves = [
        { dx: 0, dy: -1, cost: config.straightCost }, // Up
        { dx: 0, dy: 1, cost: config.straightCost },  // Down
        { dx: -1, dy: 0, cost: config.straightCost }, // Left
        { dx: 1, dy: 0, cost: config.straightCost },  // Right
        { dx: -1, dy: -1, cost: config.diagonalCost },// Top-Left
        { dx: 1, dy: -1, cost: config.diagonalCost }, // Top-Right
        { dx: -1, dy: 1, cost: config.diagonalCost }, // Bottom-Left
        { dx: 1, dy: 1, cost: config.diagonalCost }   // Bottom-Right
    ];

    for (let i = 0; i < moves.length; i++) {
        const newX = node.x + moves[i].dx;
        const newY = node.y + moves[i].dy;

        // Check if within bounds and walkable (0)
        if (newX >= 0 && newX < gridWidth && newY >= 0 && newY < gridHeight && grid[newY][newX] === 0) {
            neighbors.push({ x: newX, y: newY, moveCost: moves[i].cost });
        }
    }
    return neighbors;
}

function nodeKey(node) {
    return node.x + ',' + node.y;
}

// 3. Core A* Algorithm (De-flattened control flow)
function findRoute(start, end) {
    let openSet = {};
    let closedSet = {};
    let cameFrom = {};
    let gScore = {};
    let fScore = {};
    let iterations = 0;

    const startId = nodeKey(start);
    openSet[startId] = start;
    gScore[startId] = 0;
    fScore[startId] = calculateHeuristic(start, end);

    while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
        iterations++;

        // Find node with lowest fScore in openSet
        let currentId = null;
        let lowestF = Infinity;
        for (let key in openSet) {
            if (fScore[key] < lowestF) {
                lowestF = fScore[key];
                currentId = key;
            }
        }

        let current = openSet[currentId];

        // If we reached the destination, reconstruct the path
        if (current.x === end.x && current.y === end.y) {
            let path = [current];
            let traceKey = currentId;

            while (cameFrom[traceKey]) {
                traceKey = cameFrom[traceKey];
                // Fallback parsing just in case node data was lost
                let nodeObj = openSet[traceKey] || closedSet[traceKey] || { x: parseInt(traceKey), y: parseInt(traceKey.split(',')[1]) };
                path.unshift(nodeObj);
            }
            return { path: path, cost: gScore[currentId], iterations: iterations };
        }

        // Move current node from open to closed set
        delete openSet[currentId];
        closedSet[currentId] = current;

        // Process neighbors
        const neighbors = getNeighbors(current);
        for (let i = 0; i < neighbors.length; i++) {
            const neighbor = neighbors[i];
            const neighborId = nodeKey(neighbor);

            if (closedSet[neighborId]) continue;

            const tentativeGScore = gScore[currentId] + neighbor.moveCost;

            if (gScore[neighborId] === undefined || tentativeGScore < gScore[neighborId]) {
                cameFrom[neighborId] = currentId;
                gScore[neighborId] = tentativeGScore;
                fScore[neighborId] = tentativeGScore + calculateHeuristic(neighbor, end);
                openSet[neighborId] = neighbor;
            }
        }
    }

    // Path not found
    return { path: [], cost: Infinity, iterations: iterations };
}

// 4. Execution
const result = findRoute(startNode, endNode);
console.log("Path:", result.path.length, "Cost:", result.cost, "Iterations:", result.iterations);
